php artisan prisoner:add '{"name":"Ali Bey Hassan","first_name":"Ali","last_name":"Hassan","aka":"John J. Casson","description":"Ali Bey Hassan, born John J. Casson, was a Black Panther Party member indicted in the April 2, 1969 New York Panther 21 conspiracy case. He was held in pretrial detention and was one of the 13 defendants who went to trial and was acquitted on May 13, 1971 after the jury rejected the prosecution case built on undercover NYPD testimony.","state":"New York","race":"Black","gender":"Male","ideologies":["Black Liberation"],"affiliation":["Black Panther Party","Panther 21"],"era":"1960s","in_custody":false,"released":true,"cases":[{"institution_name":"Manhattan House of Detention (the Tombs)","institution_city":"New York","institution_state":"New York","charges":"New York state Panther 21 conspiracy counts (April 2, 1969 indictment).","arrest_date":"1969-04-02","incarceration_date":"1969-04-02","release_date":"1971-05-13","sentence":"~2 years pretrial detention; acquitted by jury, May 13, 1971.","convicted":"No - acquitted by jury, New York Supreme Court, May 13, 1971"}]}' || true

php artisan prisoner:add '{"name":"Michael Tabor","first_name":"Michael","last_name":"Tabor","aka":"Cetewayo","description":"Michael Cetewayo Tabor was a leading Harlem-based Black Panther Party theoretician and author of the influential 1970 BPP pamphlet Capitalism Plus Dope Equals Genocide. He was indicted as one of the New York Panther 21 on April 2, 1969 and held in pretrial detention before being released on bail. In February 1971, while the trial was still in session, he and co-defendant Richard Dhoruba Moore (later Dhoruba bin Wahad) jumped bail and fled the United States. Tabor settled in Algeria with the international section of the Black Panther Party and later in Zambia, where he died in 2010 having never returned to the U.S.","state":"New York","race":"Black","gender":"Male","ideologies":["Black Liberation","Pan-Africanism"],"affiliation":["Black Panther Party","Panther 21"],"era":"1960s","in_custody":false,"released":false,"in_exile":true,"currently_in_exile":false,"death_date":"2010-10-25","cases":[{"institution_name":"Manhattan House of Detention (the Tombs)","institution_city":"New York","institution_state":"New York","charges":"New York state Panther 21 conspiracy counts (April 2, 1969 indictment); fled to Algeria in February 1971 during trial.","arrest_date":"1969-04-02","incarceration_date":"1969-04-02","release_date":"1971-02-08","in_exile_since":"1971-02-08","end_of_exile":"2010-10-25","sentence":"~22 months pretrial detention before release on bail; jumped bail Feb 1971 and fled to Algeria, then Zambia. Lived in exile until his death in Zambia, October 25, 2010.","convicted":"Convicted in absentia in New York after fleeing bail."}]}' || true

