php artisan prisoner:add '{"name":"Kwando Kinshasa","first_name":"Kwando","last_name":"Kinshasa","aka":"William King","description":"Kwando Kinshasa, born William King, was a Black Panther Party member indicted in the April 2, 1969 New York Panther 21 conspiracy case. He was one of the 13 defendants who went to trial and was acquitted on May 13, 1971. He later became a professor of African-American studies and an author on incarceration and Black liberation.","state":"New York","race":"Black","gender":"Male","ideologies":["Black Liberation"],"affiliation":["Black Panther Party","Panther 21"],"era":"1960s","in_custody":false,"released":true,"cases":[{"institution_name":"Manhattan House of Detention (the Tombs)","institution_city":"New York","institution_state":"New York","charges":"New York state Panther 21 conspiracy counts (April 2, 1969 indictment).","arrest_date":"1969-04-02","incarceration_date":"1969-04-02","release_date":"1971-05-13","sentence":"~2 years pretrial detention; acquitted by jury, May 13, 1971.","convicted":"No - acquitted by jury, New York Supreme Court, May 13, 1971"}]}' || true

